              garantizar tu protección. Nunca compartas datos de contacto
              personales.
            </p>
          </div>

          {/* Chat Component */}
          <div className="flex flex-grow flex-col overflow-hidden">
            <Chat
              bookingId={bookingId}
              senderId={senderId}
              senderName={senderName}
              recipientId={recipientId}
              isFloating={true}
            />
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default FloatingChat;






