                className="grid grid-cols-1 gap-6 xl:grid-cols-2"
              >
                {[1, 2, 3, 4].map((i) => (
                  <div key={i} className="space-y-6 rounded-[32px] border border-gray-100 bg-white p-8 shadow-sm">
                    <Skeleton className="h-40 w-full rounded-3xl" />
