                  unreadPerBooking[booking.id] > 0
                    ? "bg-red-50 border-red-200 text-red-500 hover:bg-red-100 shadow-sm shadow-red-100"
                    : "bg-white border-gray-200 text-gray-400 hover:text-brand-navy hover:border-gray-300"
                )}
              >
                <MessageSquare className="h-5 w-5 shrink-0" />
                <span>Chat</span>
                {unreadPerBooking[booking.id] > 0 && (
                  <span className="flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-[9px] font-bold text-white shadow-sm animate-pulse">
                    {unreadPerBooking[booking.id]}
                  </span>
                )}
              </button>
              <span className="shrink-0 text-[10px] font-black text-gray-300 uppercase">
                REF: {booking.id.slice(0, 8)}
              </span>
            </div>
          </div>

          <AnimatePresence mode="wait">
            <div className="mb-8 flex flex-col gap-6 sm:flex-row">
              <div className="flex-grow space-y-4">
                <h4 className="text-brand-navy text-xl leading-tight font-black">
                  {booking.listingTitle}
                </h4>
                <div className="grid grid-cols-2 gap-4">
                  <div className="flex items-center text-xs font-bold text-gray-500">
                    <Calendar className="text-brand-500 mr-2 h-4 w-4" />
                    {booking.startDate &&
                    !isNaN(new Date(booking.startDate).getTime()) &&
                    booking.endDate &&
                    !isNaN(new Date(booking.endDate).getTime())
                      ? `${format(new Date(booking.startDate), 'dd/MM')} - ${format(new Date(booking.endDate), 'dd/MM/yy')}`
                      : 'Fechas inválidas'}
                  </div>
                  <div className="flex items-center text-xs font-bold text-gray-500">
                    <Users className="text-brand-500 mr-2 h-4 w-4" />
                    {booking.guests} Huéspedes
                  </div>
                </div>
                <div className="flex items-center space-x-3 rounded-2xl bg-gray-50 p-3">
                  <div className="bg-brand-navy flex h-8 w-8 items-center justify-center rounded-lg text-[10px] font-black text-white uppercase">
                    {booking.guestName?.charAt(0)}
                  </div>
                  <div className="flex flex-col">
                    <span className="text-brand-navy text-xs font-black uppercase">
                      {booking.guestName}
                    </span>
                    <span className="text-[10px] font-bold text-gray-400">
                      Inquilino
                    </span>
                  </div>
                </div>
                {booking.guestMessage && (
                  <div className="relative mt-2 rounded-2xl bg-amber-50/40 border border-amber-100 p-3 text-xs text-brand-navy">
                    <p className="font-semibold text-[9px] uppercase tracking-wider text-amber-700 mb-1">
                      Presentación del huésped:
                    </p>
                    <p className="italic text-gray-600 font-medium">
                      "{booking.guestMessage}"
                    </p>
                  </div>
                )}
              </div>

              <div className="bg-brand-navy flex w-full flex-col gap-4 rounded-3xl p-5 text-white sm:w-56">
                <div className="flex flex-col">
                  <div className="flex items-center justify-between">
                    <span className="text-brand-500 text-[9px] font-black tracking-widest uppercase">Ganancia Real</span>
                    <span className="bg-brand-500 rounded-full px-2 py-0.5 text-[8px] font-black text-brand-navy">
                      Tier {tier}%
                    </span>
                  </div>
                  <span className="text-2xl font-black">
                    ${calculateCommission(booking.totalAmount, tier).hostNetProfit.toFixed(2)}
                  </span>
                  <span className="text-[9px] font-bold text-gray-400">Total: ${booking.totalAmount}</span>
                </div>
                
                <div className="space-y-2 border-t border-white/10 pt-4">
                  <div className="flex items-center justify-between">
                    <span className="text-[8px] font-bold text-gray-400 uppercase">Cobro Check-in (80%)</span>
                    <span className="text-xs font-black text-emerald-400">${calculateCommission(booking.totalAmount, tier).ucpBalance.toFixed(2)}</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-[8px] font-bold text-gray-400 uppercase">Liquidación Garantía</span>
                    <span className="text-xs font-black text-brand-500">${calculateCommission(booking.totalAmount, tier).settlementAmount.toFixed(2)}</span>
                  </div>
                </div>

                {booking.paymentReference && (
                  <div className="mt-2 flex flex-col border-t border-white/10 pt-4">
                    <span className="text-brand-500 flex items-center gap-1 text-[10px] font-black uppercase">
                      <Hash className="h-3 w-3" /> Referencia
                    </span>
                    <span className="truncate text-xs font-black">
                      {booking.paymentReference}
                    </span>
                  </div>
                )}
              </div>
            </div>
          </AnimatePresence>

          {/* Admin Actions */}
          <div className="mt-auto space-y-4 border-t border-dashed border-gray-100 pt-6">
            {booking.status === 'AWAITING_VERIFICATION' && (
              <div className="flex flex-col gap-3">
                <div className="flex gap-3">
                  <button
                    onClick={() =>
                      handleUpdateStatus(booking, 'CONFIRMED')
                    }
                    className="flex-grow transform rounded-2xl bg-emerald-500 py-3 text-[10px] font-black tracking-widest text-white uppercase shadow-lg shadow-emerald-500/20 transition-all hover:bg-emerald-600 active:scale-95"
                  >
                    Validar Pago
                  </button>
                  <button
                    onClick={() => setBookingToReject(booking)}
                    className="transform rounded-2xl border-2 border-red-100 px-6 py-3 text-[10px] font-black tracking-widest text-red-500 uppercase transition-all hover:bg-red-50 active:scale-95"
                  >
                    Rechazar
                  </button>
                </div>
              </div>
            )}

            {booking.status === 'PENDING_APPROVAL' && (
              <button
                onClick={() => onVerifyRequest(booking)}
                className="w-full flex items-center justify-center gap-2 rounded-2xl border-2 border-brand-gold bg-white py-3 text-[10px] font-black tracking-widest text-brand-navy uppercase shadow-sm transition-all hover:bg-brand-gold/10 active:scale-95"
                aria-label={`Verificar solicitud de ${booking.guestName}`}
              >
                Verificar Solicitud →
              </button>
            )}

            {/* Status History / Info */}
            <div className="space-y-2 rounded-2xl bg-gray-50 p-4">
              <div className="flex items-center justify-between">
                <span className="text-[8px] font-black tracking-widest text-gray-400 uppercase">
                  Actividad de la Reserva
                </span>
                {booking.verifiedBy && (
                  <span className="rounded-full bg-emerald-50 px-2 py-0.5 text-[8px] font-bold text-emerald-600">
                    Verificado por {booking.verifiedBy}
                  </span>
                )}
              </div>

              <div className="no-scrollbar max-h-24 space-y-2 overflow-y-auto pr-2">
                {booking.statusHistory?.map((h, idx) => (
                  <div
                    key={idx}
                    className="flex items-start gap-3 text-[9px]"
                  >
                    <div className="bg-brand-500 mt-1.5 h-1 w-1 shrink-0 rounded-full" />
                    <div className="flex-grow">
                      <div className="mb-0.5 flex items-center justify-between">
                        <span className="text-brand-navy font-black uppercase">
                          {h.status}
                        </span>
                        <span className="text-[8px] text-gray-400">
                          {(() => {
                            const d = getSafeDate(h.timestamp);
                            return d ? format(d, 'dd/MM HH:mm') : '';
                          })()}
                        </span>
                      </div>
                      {h.note && (
                        <p className="leading-snug text-gray-500 italic">
                          {h.note}
                        </p>
                      )}
                    </div>
                  </div>
                ))}
                {(!booking.statusHistory ||
                  booking.statusHistory.length === 0) && (
                  <p className="text-[10px] text-gray-400 italic">
                    No hay historial registrado.
                  </p>
                )}
              </div>
            </div>

            {booking.status === 'CONFIRMED' && (
              <div className="flex w-full items-center justify-center rounded-2xl border border-emerald-100 bg-emerald-50 py-3">
                <span className="text-[10px] font-black tracking-widest text-emerald-600 uppercase">
                  Reserva Asegurada ✓
                </span>
              </div>
            )}
            {booking.status === 'REJECTED' && (
              <div className="flex w-full flex-col items-center justify-center rounded-2xl border border-red-100 bg-red-50 py-3">
                <span className="text-[10px] font-black tracking-widest text-red-600 uppercase">
                  Pago Rechazado ✕
                </span>
                {booking.rejectionReason && (
                  <p className="mt-1 text-[9px] font-bold text-red-400">
                    {booking.rejectionReason}
                  </p>
                )}
              </div>
            )}
            {booking.status === 'EXPIRED' && (
              <div className="flex w-full flex-col items-center justify-center rounded-2xl border border-gray-100 bg-gray-50 py-3">
                <span className="text-[10px] font-black tracking-widest text-gray-400 uppercase">
                  Solicitud Expirada ✕
                </span>
                <p className="mt-1 text-[9px] font-medium text-gray-400">
                  Expiró automáticamente a las 24 horas sin respuesta.
                </p>
              </div>
            )}
            {booking.status === 'PENDING_PAYMENT' && (
              <div className="flex w-full flex-col items-center justify-center rounded-2xl bg-amber-50 py-3">
                <span className="text-[10px] font-black tracking-widest text-amber-600 uppercase">
                  Esperando comprobante del Huésped
                </span>
                <div className="mt-2">
                  <button
                    onClick={() => setBookingToCancel(booking)}
                    className="text-[8px] font-black tracking-tighter text-amber-700 uppercase underline"
                  >
                    Forzar Cancelación
                  </button>
                </div>
              </div>
            )}
          </div>
        </motion.div>
      )})}
      
      <PromptDialog
        isOpen={!!bookingToReject}
        onClose={() => setBookingToReject(null)}
        onConfirm={(reason) => {
          if (bookingToReject) {
            handleUpdateStatus(bookingToReject, 'REJECTED', reason);
          }
        }}
        title="Rechazar Reserva"
        message="Indica la razón del rechazo para que el huésped esté informado:"
        placeholder="Razón del rechazo..."
        confirmText="Rechazar Pago"
        required
      />

      <ConfirmDialog
        isOpen={!!bookingToCancel}
        onClose={() => setBookingToCancel(null)}
        onConfirm={() => {
          if (bookingToCancel) {
            handleUpdateStatus(bookingToCancel, 'CANCELLED', 'Cancelada por administrador');
          }
        }}
        title="Forzar Cancelación"
        message="¿Deseas cancelar esta reserva por falta de pago? Esta acción no se puede deshacer."
        confirmText="Sí, Cancelar"
        isDestructive
      />
    </div>
  );
};

export default BookingList;
","usedDeprecatedRules":[]},{"filePath":"C:\VeneStay\src\features\dashboard\components\DashboardHeader.tsx","messages":[],"suppressedMessages":[],"errorCount":0,"fatalErrorCount":0,"warningCount":0,"fixableErrorCount":0,"fixableWarningCount":0,"usedDeprecatedRules":[]},{"filePath":"C:\VeneStay\src\features\dashboard\components\DeleteConfirmationModal.tsx","messages":[],"suppressedMessages":[],"errorCount":0,"fatalErrorCount":0,"warningCount":0,"fixableErrorCount":0,"fixableWarningCount":0,"usedDeprecatedRules":[]},{"filePath":"C:\VeneStay\src\features\dashboard\components\GuestRequestVerificationDrawer.tsx","messages":[{"ruleId":"@typescript-eslint/no-unused-vars","severity":1,"message":"'Hash' is defined but never used.","line":10,"column":3,"nodeType":"Identifier","messageId":"unusedVar","endLine":10,"endColumn":7,"suggestions":[{"messageId":"removeUnusedVar","data":{"varName":"Hash"},"fix":{"range":[190,200],"text":""},"desc":"Remove unused variable "Hash"."}]},{"ruleId":"@typescript-eslint/no-unused-vars","severity":1,"message":"'Award' is defined but never used.","line":15,"column":3,"nodeType":"Identifier","messageId":"unusedVar","endLine":15,"endColumn":8,"suggestions":[{"messageId":"removeUnusedVar","data":{"varName":"Award"},"fix":{"range":[252,263],"text":""},"desc":"Remove unused variable "Award"."}]},{"ruleId":"@typescript-eslint/no-unused-vars","severity":1,"message":"'BookingStatus' is defined but never used.","line":22,"column":19,"nodeType":"Identifier","messageId":"unusedVar","endLine":22,"endColumn":32,"suggestions":[{"messageId":"removeUnusedVar","data":{"varName":"BookingStatus"},"fix":{"range":[458,473],"text":""},"desc":"Remove unused variable "BookingStatus"."}]}],"suppressedMessages":[],"errorCount":0,"fatalErrorCount":0,"warningCount":3,"fixableErrorCount":0,"fixableWarningCount":0,"source":"import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { 
  X, 
  Check, 
  Loader2, 
  AlertCircle, 
  Calendar, 
  Users, 
  Hash, 
  MessageSquare, 
  Shield, 
  Mail, 
  Phone, 
  Award,
  Clock,
  AlertTriangle,
  UserCheck
} from 'lucide-react';
import { format, parseISO, isWithinInterval, startOfDay } from 'date-fns';
import { cn } from '@/lib/utils';
import { Booking, BookingStatus } from '@/types';
import { calculateCommission, CommissionTier } from '@/lib/commission';
import { useGuestProfile } from '../hooks/useGuestProfile';
import { useListingPaymentMethods } from '@/features/listings/hooks/useListingPaymentMethods';
import { approveBookingRequestWithDetails, rejectBookingRequest } from '@/services/booking-request.service';
import { toast } from 'sonner';
import { z } from 'zod';

const rejectionReasonSchema = z.string()
  .min(10, 'El motivo de rechazo debe tener al menos 10 caracteres.')
  .max(300, 'El motivo de rechazo no puede superar los 300 caracteres.');

interface GuestRequestVerificationDrawerProps {
  booking: Booking | null;
  isOpen: boolean;
  onClose: () => void;
  onApproveSuccess?: (bookingId: string) => void;
  onRejectSuccess?: (bookingId: string) => void;
  onOpenChat: (booking: Booking) => void;
  allBookings: Booking[];
  tier: CommissionTier;
}

const GuestRequestVerificationDrawer: React.FC<GuestRequestVerificationDrawerProps> = ({
  booking,
  isOpen,
  onClose,
  onApproveSuccess,
  onRejectSuccess,
  onOpenChat,
  allBookings,
  tier
}) => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showRejectDialog, setShowRejectDialog] = useState(false);
  const [rejectionReason, setRejectionReason] = useState('');
  const [rejectionError, setRejectionError] = useState('');
  const [timeLeft, setTimeLeft] = useState('');
  const [timeWarning, setTimeWarning] = useState(false);
  
  const [hostNote, setHostNote] = useState('');
  const [selectedPaymentDataIdx, setSelectedPaymentDataIdx] = useState<number>(0);

  // Hooks
  const { paymentMethods: listingPaymentMethods } = useListingPaymentMethods(booking?.listingId);
  const { guestProfile, trustScore, isLoading: isProfileLoading } = useGuestProfile(booking?.guestId);

  // Expiration countdown effect
  useEffect(() => {
    if (!booking?.expiresAt || !isOpen) return;

    const calculateTime = () => {
      const difference = new Date(booking.expiresAt!).getTime() - new Date().getTime();
      if (difference <= 0) {
        setTimeLeft('Expirado');
        return;
      }
      
      const hours = Math.floor(difference / (1000 * 60 * 60));
      const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((difference % (1000 * 60)) / 1000);

      setTimeLeft(`${hours}h ${minutes}m ${seconds}s`);
      
      // Warning if less than 2 hours left
      if (difference < 2 * 60 * 60 * 1000) {
        setTimeWarning(true);
      } else {
        setTimeWarning(false);
      }
    };

    calculateTime();
    const interval = setInterval(calculateTime, 1000);
    return () => clearInterval(interval);
  }, [booking?.expiresAt, isOpen]);

  if (!booking) return null;

  // Conflict calculation
  const isConflicting = allBookings.some(b => {
    if (b.id === booking.id || b.listingId !== booking.listingId) return false;
    if (booking.status === 'REJECTED' || booking.status === 'CANCELLED' || booking.status === 'EXPIRED') return false;
    if (b.status === 'REJECTED' || b.status === 'CANCELLED' || b.status === 'EXPIRED') return false;

    try {
      const start1 = startOfDay(parseISO(booking.startDate));
      const end1 = startOfDay(parseISO(booking.endDate));
      const start2 = startOfDay(parseISO(b.startDate));
      const end2 = startOfDay(parseISO(b.endDate));

      return (
        isWithinInterval(start1, { start: start2, end: end2 }) ||
        isWithinInterval(end1, { start: start2, end: end2 }) ||
        isWithinInterval(start2, { start: start1, end: end1 })
      );
    } catch {
      return false;
    }
  });

  // UCP Calculations
  const commission = calculateCommission(booking.totalAmount, tier);

  const handleApproveWithDetails = async () => {
    try {
      setIsSubmitting(true);
      const selectedPayment = listingPaymentMethods[selectedPaymentDataIdx];
      const paymentInstructions = selectedPayment 
        ? `${selectedPayment.label} - ${selectedPayment.type}\nDetalles adicionales provistos por el anfitrión en su perfil.`
        : 'Pago Móvil (o método predeterminado).';
        
      await approveBookingRequestWithDetails(booking.id, hostNote, paymentInstructions, booking.ownerId, selectedPayment);
      toast.success('Solicitud de reserva aprobada con éxito');
      if (onApproveSuccess) onApproveSuccess(booking.id);
      onClose();
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Error al aprobar la reserva.';
      toast.error(message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReject = async () => {
    const validation = rejectionReasonSchema.safeParse(rejectionReason);
    if (!validation.success) {
      setRejectionError(validation.error.issues[0].message);
      return;
    }

    try {
      setIsSubmitting(true);
      setRejectionError('');
      await rejectBookingRequest(booking.id, rejectionReason);
      toast.success('Solicitud de reserva rechazada');
      if (onRejectSuccess) onRejectSuccess(booking.id);
      setShowRejectDialog(false);
      onClose();
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Error al rechazar la reserva.';
      toast.error(message);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Radial SVG Arc calculations for Trust Score
  const radius = 24;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (trustScore / 100) * circumference;

  // Adaptive Trust Score Color
  const trustColorClass = trustScore < 40 
    ? 'text-red-500 stroke-red-500' 
    : trustScore < 80 
      ? 'text-brand-500 stroke-brand-500' 
      : 'text-emerald-500 stroke-emerald-500';

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Overlay */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-brand-navy/60 backdrop-blur-sm z-[120]"
          />

          {/* Drawer Container */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed top-0 right-0 bottom-0 w-full max-w-lg bg-white shadow-2xl z-[130] flex flex-col no-scrollbar overflow-y-auto"
            role="dialog"
            aria-labelledby="drawer-title"
          >
            {/* Header */}
            <div className="bg-brand-navy p-6 text-white flex items-center justify-between shrink-0">
              <div>
                <span className="text-[10px] font-black tracking-widest text-brand-500 uppercase">
                  Verificar Solicitud
                </span>
                <h3 id="drawer-title" className="text-lg font-black mt-1 leading-tight">
                  Ref: #{booking.id.slice(0, 8).toUpperCase()}
                </h3>
              </div>
              <div className="flex items-center gap-3">
                {booking.expiresAt && (
                  <div className={cn(
                    "flex items-center gap-1 rounded-full border px-3 py-1 text-[9px] font-black tracking-widest uppercase",
                    timeWarning 
                      ? "border-red-500/30 bg-red-500/10 text-red-400 animate-pulse" 
                      : "border-amber-500/30 bg-amber-500/10 text-amber-500"
                  )} aria-live="polite">
                    <Clock className="h-3 w-3" />
                    <span>{timeLeft}</span>
                  </div>
                )}
                <button 
                  onClick={onClose}
                  className="rounded-xl bg-white/10 p-2 text-white hover:bg-white/20 transition-all active:scale-95"
                  aria-label="Cerrar panel de verificación"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>
            </div>

            {/* Content Body */}
            <div className="flex-grow p-6 space-y-6 overflow-y-auto no-scrollbar">
              {/* Conflict Alerter */}
              {isConflicting && (
                <div className="rounded-2xl border border-red-200 bg-red-50/50 p-4 flex gap-3 text-red-700 animate-pulse">
                  <AlertTriangle className="h-5 w-5 shrink-0 text-red-500" />
                  <div className="text-xs">
                    <p className="font-black uppercase tracking-wider text-[9px] mb-1">
                      Alerta de Solapamiento
                    </p>
                    <p className="font-semibold leading-relaxed">
                      Tienes otra reserva que se superpone con estas fechas. Verifica tu calendario antes de aprobar.
                    </p>
                  </div>
                </div>
              )}

              {/* Guest Pasaporte Section */}
              <div className="rounded-3xl border border-gray-100 bg-gray-50/40 p-5 space-y-4" aria-label="Pasaporte del huésped">
                <div className="flex items-center justify-between">
                  <span className="text-[10px] font-black tracking-widest text-gray-400 uppercase">
                    Pasaporte VeneStay
                  </span>
                  {guestProfile?.isIdentityVerified && (
                    <span className="rounded-full bg-emerald-100/50 border border-emerald-200 px-2 py-0.5 text-[8px] font-black tracking-wider text-emerald-600 uppercase flex items-center gap-1">
                      <UserCheck className="h-2.5 w-2.5" /> Verificado
                    </span>
                  )}
                </div>

                {isProfileLoading ? (
                  <div className="flex items-center gap-4 animate-pulse">
                    <div className="h-14 w-14 rounded-full bg-gray-200" />
                    <div className="space-y-2 flex-grow">
                      <div className="h-4 bg-gray-200 rounded w-1/3" />
                      <div className="h-3 bg-gray-200 rounded w-1/2" />
                    </div>
                  </div>
                ) : (
                  <div className="flex items-center justify-between gap-4">
                    {/* Guest Main Info */}
                    <div className="flex items-center gap-4">
                      {guestProfile?.photoURL ? (
                        <img 
                          src={guestProfile.photoURL} 
                          alt={booking.guestName}
                          className="h-14 w-14 rounded-full object-cover border-2 border-brand-gold/30 shadow-sm"
                        />
                      ) : (
                        <div className="h-14 w-14 rounded-full bg-brand-navy text-white flex items-center justify-center font-black text-xl border-2 border-brand-gold/30 shadow-sm">
                          {booking.guestName?.charAt(0).toUpperCase()}
                        </div>
                      )}
                      <div>
                        <h4 className="text-brand-navy font-black text-sm uppercase">
                          {booking.guestName}
                        </h4>
                        <p className="text-[10px] font-semibold text-gray-400 mt-0.5">
                          Huésped de la plataforma
                        </p>
                        {/* KYC badges */}
                        <div className="flex items-center gap-1.5 mt-2">
                          <span 
                            className={cn(
                              "p-1 rounded-lg border",
                              guestProfile?.isEmailVerified ? "border-emerald-100 bg-emerald-50 text-emerald-600" : "border-gray-200 bg-white text-gray-400"
                            )} 
                            title={guestProfile?.isEmailVerified ? "Correo verificado" : "Correo sin verificar"}
                          >
                            <Mail className="h-3 w-3" />
                          </span>
                          <span 
                            className={cn(
                              "p-1 rounded-lg border",
                              guestProfile?.isPhoneVerified ? "border-emerald-100 bg-emerald-50 text-emerald-600" : "border-gray-200 bg-white text-gray-400"
                            )}
                            title={guestProfile?.isPhoneVerified ? "Teléfono verificado" : "Teléfono sin verificar"}
                          >
                            <Phone className="h-3 w-3" />
                          </span>
                          <span 
                            className={cn(
                              "p-1 rounded-lg border",
                              guestProfile?.isIdentityVerified ? "border-emerald-100 bg-emerald-50 text-emerald-600" : "border-gray-200 bg-white text-gray-400"
                            )}
                            title={guestProfile?.isIdentityVerified ? "Identidad verificado" : "Identidad sin verificar"}
                          >
                            <Shield className="h-3 w-3" />
                          </span>
                        </div>
                      </div>
                    </div>

                    {/* Radial SVG Trust Score */}
                    <div className="flex flex-col items-center justify-center shrink-0">
                      <div className="relative h-14 w-14 flex items-center justify-center">
                        <svg className="absolute transform -rotate-90 w-14 h-14">
                          {/* Background Circle */}
                          <circle
                            cx="28"
                            cy="28"
                            r={radius}
                            className="stroke-gray-100 fill-none"
                            strokeWidth="3.5"
                          />
                          {/* Animated Foreground Circle */}
                          <motion.circle
                            cx="28"
                            cy="28"
                            r={radius}
                            className={cn("fill-none", trustColorClass)}
                            strokeWidth="3.5"
                            strokeDasharray={circumference}
                            initial={{ strokeDashoffset: circumference }}
                            animate={{ strokeDashoffset }}
                            transition={{ duration: 0.8, ease: "easeOut" }}
                          />
                        </svg>
                        <span className={cn("text-xs font-black", trustColorClass)}>
                          {trustScore}%
                        </span>
                      </div>
                      <span className="text-[8px] font-black uppercase tracking-wider text-gray-400 mt-1">
                        Confianza
                      </span>
                    </div>
                  </div>
                )}
              </div>

              {/* Booking Details */}
              <div className="space-y-4">
                <h4 className="text-brand-navy font-black text-sm uppercase border-b border-gray-100 pb-2">
                  Detalles de la Reserva
                </h4>
                <p className="text-brand-navy text-base font-black leading-tight">
                  {booking.listingTitle}
                </p>
                <div className="grid grid-cols-2 gap-4">
                  <div className="flex items-center text-xs font-bold text-gray-500 bg-gray-50 px-4 py-3 rounded-2xl">
                    <Calendar className="text-brand-500 mr-2 h-4 w-4 shrink-0" />
                    <div className="flex flex-col">
                      <span className="text-[9px] text-gray-400 uppercase font-bold">Fechas</span>
                      <span>
                        {booking.startDate && booking.endDate
                          ? `${format(new Date(booking.startDate), 'dd/MM')} - ${format(new Date(booking.endDate), 'dd/MM/yy')}`
                          : 'Pendiente'}
                      </span>
                    </div>
                  </div>
                  <div className="flex items-center text-xs font-bold text-gray-500 bg-gray-50 px-4 py-3 rounded-2xl">
                    <Users className="text-brand-500 mr-2 h-4 w-4 shrink-0" />
                    <div className="flex flex-col">
                      <span className="text-[9px] text-gray-400 uppercase font-bold">Huéspedes</span>
                      <span>{booking.guests} Viajeros</span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Guest Message Presentation */}
              {booking.guestMessage && (
                <div className="rounded-3xl border border-amber-100 bg-amber-50/20 p-5 space-y-2">
                  <span className="text-[9px] font-black tracking-widest text-amber-700 uppercase flex items-center gap-1">
                    <MessageSquare className="h-3.5 w-3.5" /> Presentación del huésped
                  </span>
                  <p className="text-xs italic text-gray-600 font-semibold leading-relaxed">
                    "{booking.guestMessage}"
                  </p>
                </div>
              )}

              {/* UCP Earnings Breakdown */}
              <div className="space-y-4">
                <h4 className="text-brand-navy font-black text-sm uppercase border-b border-gray-100 pb-2">
                  Desglose Financiero (Garantía 20% / Saldo 80%)
                </h4>
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Gold Circle: Anticipo (20%) */}
                  <div className="border border-brand-gold/20 bg-brand-gold/5 rounded-3xl p-4 flex flex-col justify-between h-28">
                    <div>
                      <span className="text-[9px] font-black tracking-wider text-brand-500 uppercase flex items-center gap-1">
                        <span className="h-1.5 w-1.5 rounded-full bg-brand-500" /> Anticipo Garantía (20%)
                      </span>
                      <p className="text-2xl font-black text-brand-navy mt-2">
                        ${commission.hostNetProfit ? (booking.totalAmount * 0.2).toFixed(2) : '0.00'}
                      </p>
                    </div>
                    <span className="text-[8px] font-bold text-gray-400">
                      Huésped lo transfiere hoy
                    </span>
                  </div>

                  {/* Navy Circle: Saldo Check-In (80%) */}
                  <div className="border border-brand-navy/10 bg-brand-navy/5 rounded-3xl p-4 flex flex-col justify-between h-28">
                    <div>
                      <span className="text-[9px] font-black tracking-wider text-brand-navy uppercase flex items-center gap-1">
                        <span className="h-1.5 w-1.5 rounded-full bg-brand-navy" /> Saldo Check-in (80%)
                      </span>
                      <p className="text-2xl font-black text-brand-navy mt-2">
                        ${commission.ucpBalance ? commission.ucpBalance.toFixed(2) : '0.00'}
                      </p>
                    </div>
                    <span className="text-[8px] font-bold text-gray-400">
                      Pagas directamente al anfitrión
                    </span>
                  </div>
                </div>

                {/* Net Earnings Summary */}
                <div className="bg-brand-navy text-white rounded-3xl p-5 flex items-center justify-between">
                  <div className="space-y-1">
                    <span className="text-[9px] font-black tracking-widest text-brand-500 uppercase">
                      Ingreso Neto Neto
                    </span>
                    <h3 className="text-3xl font-black">
                      ${commission.hostNetProfit ? commission.hostNetProfit.toFixed(2) : '0.00'}
                    </h3>
                  </div>
                  <div className="text-right text-[10px] space-y-1 font-semibold text-gray-400">
                    <p>Total: ${booking.totalAmount}</p>
                    <p>Plataforma: -${(booking.totalAmount * (100 - tier) / 100).toFixed(2)}</p>
                  </div>
                </div>
              </div>
              {/* Respuesta y Datos de Pago al Inquilino (Paso 2) */}
              <div className="bg-slate-50 border border-slate-200 rounded-3xl p-5 space-y-4">
                <label className="text-brand-navy block text-[9px] font-black tracking-widest uppercase">
                  Respuesta y Datos de Pago al Inquilino (Paso 2)
                </label>
                
                <textarea
                  value={hostNote}
                  onChange={(e) => setHostNote(e.target.value)}
                  placeholder="Ej: ¡Hola! Con gusto te recibimos en Lechería. Adjunto mis datos para completar la garantía..."
                  className="w-full h-20 rounded-2xl border border-gray-200 bg-white p-3 text-xs outline-none focus:ring-1 focus:ring-brand-gold"
                />

                <div className="space-y-2">
                  <label className="text-[8px] font-black tracking-widest text-gray-400 uppercase">
                    Seleccionar Cuenta de Pago de la Propiedad
                  </label>
                  <select 
                    value={selectedPaymentDataIdx}
                    onChange={(e) => setSelectedPaymentDataIdx(Number(e.target.value))}
                    className="w-full rounded-xl border border-gray-200 bg-white p-2.5 text-xs font-bold focus:ring-1 focus:ring-brand-gold outline-none"
                  >
                    {listingPaymentMethods.map((method, idx) => (
                      <option key={idx} value={idx}>
                        {method.label} ({method.type})
                      </option>
                    ))}
                    {listingPaymentMethods.length === 0 && (
                      <option value="-1">Sin métodos registrados (Usar predeterminado)</option>
                    )}
                  </select>
                </div>
              </div>
            </div>

            {/* Actions Bar Footer */}
            <div className="bg-gray-50 border-t border-gray-100 p-6 shrink-0 flex items-center gap-4">
              <button
                disabled={isSubmitting}
                onClick={() => onOpenChat(booking)}
                className="bg-white border border-gray-200 text-brand-navy hover:bg-gray-100 flex items-center justify-center gap-2 rounded-2xl py-4 px-6 text-[10px] font-black tracking-widest uppercase shadow-sm transition-all shrink-0"
                aria-label="Iniciar chat de conversación"
              >
                <MessageSquare className="h-4 w-4" />
              </button>

              <button
                disabled={isSubmitting || !hostNote.trim()}
                onClick={handleApproveWithDetails}
                className="bg-emerald-500 hover:bg-emerald-600 text-white flex-grow flex items-center justify-center gap-2 rounded-2xl py-4 px-6 text-[10px] font-black tracking-widest uppercase shadow-xl shadow-emerald-500/10 transition-all disabled:opacity-50"
                aria-label={`Aprobar solicitud de reserva`}
              >
                {isSubmitting ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4" />}
                Aprobar y Enviar Datos
              </button>

              <button
                disabled={isSubmitting}
                onClick={() => setShowRejectDialog(true)}
                className="bg-white border border-red-200 text-red-500 hover:bg-red-50 flex items-center justify-center gap-2 rounded-2xl py-4 px-6 text-[10px] font-black tracking-widest uppercase shadow-sm transition-all"
                aria-label={`Rechazar solicitud`}
              >
                Rechazar
              </button>
            </div>

            {/* Inline Reject Dialog Modal */}
            <AnimatePresence>
              {showRejectDialog && (
                <div className="fixed inset-0 z-[140] flex items-center justify-center bg-brand-navy/80 p-4 backdrop-blur-md">
                  <motion.div
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.95 }}
                    className="bg-white p-6 rounded-3xl shadow-2xl max-w-sm w-full space-y-6"
                  >
                    <div>
                      <h3 className="text-lg font-black text-brand-navy">Rechazar Solicitud</h3>
                      <p className="text-xs text-gray-500 mt-2 font-medium">
                        Por favor, proporciona el motivo del rechazo para que el huésped esté debidamente informado:
                      </p>
                    </div>

                    <div className="space-y-2">
                      <textarea
                        value={rejectionReason}
                        onChange={(e) => setRejectionReason(e.target.value)}
                        placeholder="Escribe el motivo del rechazo (mín. 10 caracteres)..."
                        className="w-full h-24 rounded-2xl border border-gray-200 p-3 text-xs focus:ring-1 focus:ring-brand-gold outline-none font-medium resize-none"
                      />
                      {rejectionError && (
                        <p className="text-[10px] text-red-500 font-bold flex items-center gap-1">
                          <AlertCircle className="h-3 w-3 shrink-0" /> {rejectionError}
                        </p>
                      )}
                    </div>

                    <div className="flex gap-3">
                      <button
                        onClick={() => {
                          setShowRejectDialog(false);
                          setRejectionReason('');
                          setRejectionError('');
                        }}
                        className="flex-grow py-3.5 bg-gray-100 text-gray-500 rounded-xl font-bold uppercase tracking-widest text-[9px] hover:bg-gray-200 transition-colors"
                      >
                        Cancelar
                      </button>
                      <button
                        onClick={handleReject}
                        className="flex-grow py-3.5 bg-red-500 text-white rounded-xl font-bold uppercase tracking-widest text-[9px] hover:bg-red-600 transition-colors shadow-lg shadow-red-500/20"
                      >
                        Confirmar Rechazo
                      </button>
                    </div>
                  </motion.div>
                </div>
              )}
            </AnimatePresence>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default GuestRequestVerificationDrawer;
","usedDeprecatedRules":[]},{"filePath":"C:\VeneStay\src\features\dashboard\components\KYCAuditPanel.tsx","messages":[],"suppressedMessages":[],"errorCount":0,"fatalErrorCount":0,"warningCount":0,"fixableErrorCount":0,"fixableWarningCount":0,"usedDeprecatedRules":[]},{"filePath":"C:\VeneStay\src\features\dashboard\components\ListingForm.tsx","messages":[{"ruleId":"@typescript-eslint/no-unused-vars","severity":1,"message":"'setShowWarningModal' is defined but never used.","line":40,"column":24,"nodeType":"Identifier","messageId":"unusedVar","endLine":40,"endColumn":43},{"ruleId":"@typescript-eslint/no-unused-vars","severity":1,"message":"'loadError' is defined but never used.","line":374,"column":3,"nodeType":"Identifier","messageId":"unusedVar","endLine":374,"endColumn":12},{"ruleId":"react-hooks/exhaustive-deps","severity":1,"message":"React Hook useEffect has missing dependencies: 'editingListing.id' and 'setEditingListing'. Either include them or remove the dependency array. If 'setEditingListing' changes too often, find the parent component that defines it and wrap that definition in useCallback.","line":415,"column":6,"nodeType":"ArrayExpression","endLine":415,"endColumn":8,"suggestions":[{"desc":"Update the dependencies array to be: [editingListing.id, setEditingListing]","fix":{"range":[18542,18544],"text":"[editingListing.id, setEditingListing]"}}]}],"suppressedMessages":[],"errorCount":0,"fatalErrorCount":0,"warningCount":3,"fixableErrorCount":0,"fixableWarningCount":0,"source":"import React, { useState, useEffect, Suspense, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'motion/react';
import { X, Check, Loader2, ArrowLeft, ArrowRight, AlertCircle } from 'lucide-react';
import { Listing } from '@/types';
import { listingSchema } from '../types/dashboard.schema';
import { cn } from '@/lib/utils';
import { useListingValidation, FormStepState } from '../hooks/useListingValidation';
import { toast } from 'sonner';
import { useListingForm, ListingFormProvider } from './ListingFormContext';
import StepGeneral from './form-steps/StepGeneral';

const StepGallery = React.lazy(() => import('./form-steps/StepGallery'));
const StepMap = React.lazy(() => import('./form-steps/StepMap'));
const StepPayments = React.lazy(() => import('./form-steps/StepPayments'));

interface ListingFormProps {
  editingListing: Listing;
  setEditingListing: React.Dispatch<React.SetStateAction<Listing | null>>;
  handleUpdateListing: (e: React.FormEvent, listing?: Listing) => Promise<void>;
  isSaving: boolean;
  isUploading: boolean;
  handleImageUpload: (e: React.ChangeEvent<HTMLInputElement> | { files: FileList }, environmentId?: string) => Promise<void>;
  removeImage: (index: number) => void;
  isLoaded: boolean;
  loadError: { message: string } | null;
  LECHERIA_CENTER: { lat: number; lng: number };
  DEFAULT_MAP_OPTIONS: google.maps.MapOptions;
  user: { uid: string; displayName?: string; photoURL?: string } | null;
}

const ListingFormContent: React.FC<{
  step: number;
  setStep: React.Dispatch<React.SetStateAction<number>>;
  setShowWarningModal: React.Dispatch<React.SetStateAction<boolean>>;
  isPublished: boolean;
  handleSubmit: (e: React.FormEvent) => Promise<void>;
  initialListingSnapshot: React.MutableRefObject<Listing | null>;
  handleCloseAttempt: () => void;
}> = ({ step, setStep, setShowWarningModal, isPublished, handleSubmit, initialListingSnapshot, handleCloseAttempt }) => {
  const { editingListing, isSaving, isUploading, validation, setEditingListing: contextSetEditingListing } = useListingForm();
  const { isStepValid, validateStep, errors } = validation;
  const navigate = useNavigate();

  const isStepModified = (currentStep: number): boolean => {
    if (editingListing.id.startsWith('listing-')) return false;
    if (!initialListingSnapshot.current) return false;

    const currentData = getStepData(currentStep);
    const originalListing = initialListingSnapshot.current;

    const originalData = (() => {
      switch (currentStep) {
        case 1:
          return {
            title: originalListing.title,
            description: originalListing.description,
            pricePerNight: originalListing.pricePerNight,
            city: originalListing.city,
            maxGuests: originalListing.maxGuests,
            bedrooms: originalListing.bedrooms,
            beds: originalListing.beds,
            baths: originalListing.baths,
            buildingFloors: originalListing.buildingFloors,
            propertyFloor: originalListing.propertyFloor,
            constructionYear: originalListing.constructionYear,
            minNights: originalListing.minNights,
            cancellationPolicy: originalListing.cancellationPolicy,
            bookingMode: originalListing.bookingMode,
            propertyType: originalListing.propertyType,
            accommodationType: originalListing.accommodationType,
            maxNights: originalListing.maxNights,
            isPetFriendly: originalListing.isPetFriendly,
            cleaningFee: originalListing.cleaningFee,
          };
        case 2:
          return {
            images: originalListing.images,
            environmentPhotos: originalListing.environmentPhotos,
          };
        case 3:
          return {
            latitude: originalListing.latitude,
            longitude: originalListing.longitude,
            manualAddress: originalListing.manualAddress,
          };
        case 4:
          return {
            paymentMethods: originalListing.paymentMethods,
          };
        default:
          return {};
      }
    })();

    const currentStepFields = {
      ...currentData,
      ...(currentStep === 1 ? {
        cancellationPolicy: editingListing.cancellationPolicy,
        bookingMode: editingListing.bookingMode,
      } : {})
    };

    return JSON.stringify(currentStepFields) !== JSON.stringify(originalData);
  };

  // Extracts only the fields relevant to the current step for scoped validation
  const getStepData = (currentStep: number) => {
    switch (currentStep) {
      case 1:
        return {
          title: editingListing.title,
          description: editingListing.description,
          pricePerNight: editingListing.pricePerNight,
          city: editingListing.city,
          maxGuests: editingListing.maxGuests,
          bedrooms: editingListing.bedrooms,
          beds: editingListing.beds,
          baths: editingListing.baths,
          buildingFloors: editingListing.buildingFloors,
          propertyFloor: editingListing.propertyFloor,
          constructionYear: editingListing.constructionYear,
          minNights: editingListing.minNights,
          propertyType: editingListing.propertyType,
          accommodationType: editingListing.accommodationType,
          maxNights: editingListing.maxNights,
          isPetFriendly: editingListing.isPetFriendly,
          cleaningFee: editingListing.cleaningFee,
        };
      case 2:
        return {
          images: editingListing.images,
          environmentPhotos: editingListing.environmentPhotos,
        };
      case 3:
        return {
          latitude: editingListing.latitude,
          longitude: editingListing.longitude,
          manualAddress: editingListing.manualAddress,
        };
      case 4:
        return {
          paymentMethods: editingListing.paymentMethods,
        };
      default:
        return {};
    }
  };

  const handleNextStep = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (step < 4) {
      const stepState = { step, data: getStepData(step) } as unknown as FormStepState;
      const isValid = validateStep(stepState);
      if (!isValid) {
        toast.error('Por favor completa la información requerida de este paso', {
          description: Object.values(errors)[0] as string || 'Campos requeridos faltantes'
        });
        return;
      }
    }

    setTimeout(() => {
      setStep(prev => prev + 1);
    }, 0);
  };

  return (
    <AnimatePresence mode="wait">
      {!isPublished ? (
        <motion.form
          key="listing-form-content"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onSubmit={handleSubmit}
          onKeyDown={(e) => { if (e.key === 'Enter' && e.target instanceof HTMLInputElement) e.preventDefault(); }}
          className="flex h-full flex-col md:max-h-[95vh]"
        >
          {/* Header */}
          <div className="bg-brand-navy flex shrink-0 items-center justify-between p-6 text-white md:p-8 relative overflow-hidden">
            <div className="z-10">
              <h3 className="flex items-center gap-2 text-xl font-black tracking-tight md:text-2xl">
                {editingListing.id.startsWith('listing-') ? 'Nueva Propiedad' : 'Editar Propiedad'}
              </h3>
              <div className="flex items-center gap-3 mt-1">
                <p className="text-brand-500 text-[9px] font-black tracking-[0.3em] uppercase md:text-[10px]">
                  {editingListing.id.startsWith('listing-') ? 'Publicación en Lechería' : `Ref: ${editingListing.id}`}
                </p>
                <AnimatePresence>
                  {editingListing.id.startsWith('listing-') && (
                    <motion.span 
                      key="autosave"
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0 }}
                      className="bg-white/10 text-[8px] uppercase tracking-widest px-2 py-0.5 rounded-full flex items-center gap-1 font-bold text-gray-300"
                    >
                      <Check className="h-2 w-2 text-brand-500" /> Guardado
                    </motion.span>
                  )}
                </AnimatePresence>
              </div>
            </div>
            <button type="button" onClick={handleCloseAttempt} className="rounded-2xl bg-white/10 p-3 transition-transform hover:bg-white/20 active:scale-95 z-10">
              <X className="h-6 w-6" />
            </button>
            
            {/* Dynamic Progress Bar Background */}
            <motion.div 
              className="absolute bottom-0 left-0 h-1 bg-brand-500"
              initial={{ width: 0 }}
              animate={{ width: `${(step / 4) * 100}%` }}
              transition={{ duration: 0.5, ease: "easeInOut" }}
            />
          </div>

          {/* Stepper Indicator */}
          <div className="bg-gray-50 flex items-center justify-between border-b border-gray-100 px-6 py-4 md:px-8 relative">
            <div className="absolute top-1/2 left-6 right-6 h-[2px] -translate-y-1/2 bg-gray-200 pointer-events-none md:left-8 md:right-8" />
            <motion.div 
              className="absolute top-1/2 left-6 h-[2px] -translate-y-1/2 bg-brand-navy pointer-events-none md:left-8"
              initial={{ width: 0 }}
              animate={{ width: `calc(${((step - 1) / 3) * 100}% - ${((step - 1) / 3) * 32}px)` }}
              transition={{ duration: 0.5, ease: "easeInOut" }}
            />
            {[
              { num: 1, label: 'General', copy: 'Info base' },
              { num: 2, label: 'Galería', copy: 'Sube fotos' },
              { num: 3, label: 'Mapa', copy: 'Ubicación' },
              { num: 4, label: 'Pagos', copy: 'Métodos' }
            ].map((s) => (
              <div key={s.num} className={`relative z-10 flex items-center gap-2 bg-gray-50 pr-4 md:pr-0 ${s.num === step ? 'text-brand-navy' : 'text-gray-300'}`}>
                <motion.div 
                  initial={false}
                  animate={{ 
                    scale: s.num === step ? 1.1 : 1,
                    backgroundColor: s.num === step ? '#0B1120' : s.num < step ? '#C5A059' : '#E5E7EB',
                    color: s.num <= step ? '#FFFFFF' : '#9CA3AF'
                  }}
                  className="flex h-8 w-8 md:h-6 md:w-6 items-center justify-center rounded-full text-xs font-black shadow-sm"
                >
                  {s.num < step ? <Check className="h-4 w-4 md:h-3 md:w-3" /> : s.num}
                </motion.div>
                <div className="hidden flex-col md:flex bg-gray-50 px-2">
                  <span className="text-[10px] font-bold tracking-widest uppercase">
                    {s.label}
                  </span>
                  <span className={`text-[9px] ${s.num === step ? 'text-brand-500 font-bold' : 'text-gray-400'}`}>
                    {s.copy}
                  </span>
                </div>
              </div>
            ))}
          </div>

          <div className="no-scrollbar flex-grow overflow-y-auto p-6 md:p-8">
            <Suspense fallback={<div className="flex h-full items-center justify-center"><Loader2 className="h-8 w-8 animate-spin text-brand-500" /></div>}>
              <AnimatePresence mode="wait">
                {step === 1 && <StepGeneral />}
                {step === 2 && <StepGallery />}
                {step === 3 && <StepMap />}
                {step === 4 && <StepPayments />}
              </AnimatePresence>
            </Suspense>
          </div>

          <div className="bg-gray-50 shrink-0 border-t border-gray-100 p-6 md:p-8 flex items-center justify-between gap-4">
            {step > 1 ? (
              <button type="button" onClick={() => setStep(step - 1)} className="bg-white border border-gray-200 text-brand-navy hover:bg-gray-100 flex items-center justify-center gap-2 rounded-2xl py-4 px-6 text-[10px] font-black tracking-widest uppercase shadow-sm transition-all w-1/3">
                <ArrowLeft className="h-4 w-4" /> Atrás
              </button>
            ) : (
              <div className="w-1/3"></div>
            )}

