import { Star, Send, Loader2, MessageSquareText } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { submitVerifiedReview } from '@/services/review-service';
import { toast } from 'sonner';

interface ReviewFormProps {
  listingId: string;
  guestId: string;
  guestName: string;
  reviewSessionId: string;
  onSuccess?: () => void;
}

const ReviewForm: React.FC<ReviewFormProps> = ({
  listingId,
  guestId,
  guestName,
  reviewSessionId,
  onSuccess
}) => {
  const [rating, setRating] = useState(0);
  const [hover, setHover] = useState(0);
  const [comment, setComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (rating === 0) {
      toast.error('Por favor, selecciona una calificación');
      return;
    }
    if (comment.length < 10) {
      toast.error('Tu comentario debe tener al menos 10 caracteres');
      return;
    }

    setIsSubmitting(true);
    try {
      await submitVerifiedReview({
        listingId,
        guestId,
        guestName,
        rating,
        comment,
        reviewSessionId
      }, reviewSessionId);
      
      setSubmitted(true);
      toast.success('¡Reseña publicada con éxito!');
      if (onSuccess) onSuccess();
    } catch (error) {
      console.error('Error submitting review:', error);
      toast.error('No se pudo publicar la reseña. Inténtalo de nuevo.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (submitted) {
    return (
      <motion.div 
