dentifier","messageId":"unusedVar","endLine":8,"endColumn":10,"suggestions":[{"messageId":"removeUnusedVar","data":{"varName":"getDocs"},"fix":{"range":[76,88],"text":""},"desc":"Remove unused variable "getDocs"."}]}],"suppressedMessages":[],"errorCount":0,"fatalErrorCount":0,"warningCount":1,"fixableErrorCount":0,"fixableWarningCount":0,"source":"import {
  collection,
  onSnapshot,
  query,
  doc,
  getDoc,
  where,
  getDocs,
} from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Listing } from '@/types';

export const subscribeToListings = (
  onUpdate: (listings: Listing[]) => void,
  onError?: (error: Error) => void
) => {
  const q = query(
    collection(db, 'listings'),
    where('isPublishedFromDashboard', '==', true)
  );
  return onSnapshot(
    q,
    (snapshot) => {
      const data = snapshot.docs.map((doc) => ({
        ...doc.data(),
        id: doc.id,
      })) as Listing[];
      onUpdate(data);
    },
    onError
  );
};

export const getListingById = async (id: string): Promise<Listing | null> => {
  const docRef = doc(db, 'listings', id);
  const docSnap = await getDoc(docRef);
  if (docSnap.exists()) {
    return { ...docSnap.data(), id: docSnap.id } as Listing;
  }
  return null;
